@import"https://fonts.googleapis.com/css2?family=Outfit:wght@400;600;800&family=Noto+Serif+SC:wght@400;700&display=swap";@import"https://cdn.jsdelivr.net/npm/remixicon@3.5.0/fonts/remixicon.css";:global(:root){--kenshi-sand: #d5c7b2;--kenshi-rust: #b85331;--bg3-gold: #c6a664;--bg3-dark: #0f0e11;--panel-bg: rgba(20, 18, 22, 0.75);--border-glow: rgba(198, 166, 100, 0.3);--rust-glow: rgba(184, 83, 49, 0.5)}.options-root{width:100%;box-sizing:border-box;padding:6px 0}.interactive-options-container{width:100%;box-sizing:border-box;display:flex;flex-direction:column;gap:12px;background:var(--panel-bg);backdrop-filter:blur(16px);-webkit-backdrop-filter:blur(16px);border-radius:8px;padding:28px 24px 24px 24px;border:1px solid hsla(0,0%,100%,.05);box-shadow:0 20px 40px rgba(0,0,0,.5),inset 0 1px 0 hsla(0,0%,100%,.1);position:relative;font-family:"Noto Serif SC","Outfit",serif}.interactive-options-container::before{content:"";position:absolute;top:0;left:50%;transform:translateX(-50%);width:90%;height:2px;background:linear-gradient(90deg, transparent, var(--bg3-gold), transparent);opacity:.6}.action-gear-btn{position:absolute;top:10px;right:14px;width:36px;height:36px;background:radial-gradient(circle at 30% 30%, #3a332e, #1a1514 70%);border:1px solid rgba(198,166,100,.65);border-radius:50%;display:flex;justify-content:center;align-items:center;color:#e5d1a4;cursor:pointer;box-shadow:0 6px 14px rgba(0,0,0,.55),inset 0 1px 2px hsla(0,0%,100%,.15),inset 0 -1px 2px rgba(0,0,0,.5);transition:transform .25s ease,box-shadow .25s ease,background .25s ease;z-index:10}.action-gear-btn::before{content:"";position:absolute;inset:-6px;border-radius:50%;border:1px solid rgba(198,166,100,.25);box-shadow:0 0 10px rgba(198,166,100,.2)}.action-gear-btn:hover{transform:rotate(25deg) scale(1.05);background:radial-gradient(circle at 30% 30%, #5a2f24, #2b1714 70%);color:#fff4d6;border-color:rgba(184,83,49,.8);box-shadow:0 8px 18px rgba(0,0,0,.6),0 0 10px rgba(184,83,49,.35)}.special-actions-menu{position:absolute;top:52px;right:14px;background:rgba(15,14,17,.95);backdrop-filter:blur(10px);border:1px solid rgba(198,166,100,.3);border-radius:6px;padding:8px 0;min-width:120px;max-height:min(60vh,360px);overflow-y:auto;box-shadow:0 10px 25px rgba(0,0,0,.8);z-index:9;opacity:0;pointer-events:none;transform:translateY(-15px) scale(0.95);transform-origin:top right;transition:all .3s cubic-bezier(0.2, 0.8, 0.2, 1)}.special-actions-menu.active{opacity:1;pointer-events:auto;transform:translateY(0) scale(1)}.special-action-item{width:100%;padding:10px 20px;color:var(--kenshi-sand);font-size:.95rem;cursor:pointer;transition:all .2s ease;position:relative;text-align:center;letter-spacing:2px;background:rgba(0,0,0,0);border:none}.option-count-4 .special-actions-menu,.option-count-5 .special-actions-menu,.option-count-6 .special-actions-menu,.option-count-7 .special-actions-menu,.option-count-8 .special-actions-menu{max-height:min(50vh,300px)}.option-count-4 .special-action-item,.option-count-5 .special-action-item,.option-count-6 .special-action-item,.option-count-7 .special-action-item,.option-count-8 .special-action-item{padding:8px 16px;font-size:.88rem;letter-spacing:1.5px}.option-count-4 .interactive-options-container,.option-count-5 .interactive-options-container,.option-count-6 .interactive-options-container,.option-count-7 .interactive-options-container,.option-count-8 .interactive-options-container{gap:10px;padding:24px 20px 20px 20px}.special-action-item:hover{background:linear-gradient(90deg, transparent, rgba(184, 83, 49, 0.4), transparent);color:#fff;text-shadow:0 0 8px hsla(0,0%,100%,.5)}.trpg-option{display:flex;align-items:center;padding:14px 20px;background:linear-gradient(90deg, rgba(255, 255, 255, 0.02) 0%, transparent 100%);border-left:3px solid hsla(0,0%,100%,.1);border-radius:4px;cursor:pointer;transition:transform .3s cubic-bezier(0.25, 0.8, 0.25, 1),box-shadow .3s ease,border-color .3s ease,background .3s ease;position:relative;overflow:hidden;text-decoration:none;color:var(--kenshi-sand);text-align:left;border:none;background-size:1px 1px;background-repeat:no-repeat}.trpg-option:hover{transform:translateX(12px);background:linear-gradient(90deg, rgba(184, 83, 49, 0.15) 0%, rgba(198, 166, 100, 0.05) 100%);border-left:3px solid var(--kenshi-rust);box-shadow:-6px 0 20px -5px var(--rust-glow)}.fight-option{border-left:3px solid rgba(239,68,68,.85);background:linear-gradient(90deg, rgba(239, 68, 68, 0.12) 0%, rgba(198, 166, 100, 0.05) 100%);box-shadow:0 0 18px rgba(239,68,68,.25)}.fight-option:hover{transform:translateX(12px) scale(1.01);background:linear-gradient(90deg, rgba(239, 68, 68, 0.22) 0%, rgba(198, 166, 100, 0.08) 100%);border-left:3px solid #ef4444;box-shadow:-6px 0 26px rgba(239,68,68,.45)}.fight-tag{display:inline-flex;align-items:center;justify-content:center;padding:2px 8px;margin-right:10px;border-radius:999px;background:rgba(239,68,68,.2);border:1px solid rgba(239,68,68,.6);color:#ffd6d6;font-size:.8rem;letter-spacing:2px}.option-badge{display:flex;justify-content:center;align-items:center;width:28px;height:28px;background:rgba(0,0,0,.5);border:1px solid var(--bg3-gold);color:var(--bg3-gold);font-family:"Outfit",sans-serif;font-weight:800;font-size:.9rem;border-radius:4px;margin-right:16px;flex-shrink:0;transition:all .3s ease;transform:rotate(45deg)}.option-badge span{transform:rotate(-45deg)}.trpg-option:hover .option-badge{background:var(--kenshi-rust);color:#fff;border-color:var(--kenshi-rust);box-shadow:0 0 12px var(--rust-glow)}.option-text{flex-grow:1;font-size:1.05rem;letter-spacing:.5px;z-index:1;line-height:1.5}.ripple{display:none}.fade-in-up{animation:fadeInUp .6s cubic-bezier(0.2, 0.8, 0.2, 1) both}@keyframes fadeInUp{from{opacity:0;transform:translateY(15px)}to{opacity:1;transform:translateY(0)}}.empty-state{width:100%;padding:12px 16px;border:1px dashed hsla(0,0%,100%,.15);border-radius:6px;color:hsla(0,0%,100%,.6);text-align:center;font-size:.95rem}